In this section, you can learn how to connect to your deployment and run the
sample query against the indexed collections in the `sample_analytics` database.

The following query uses the following stages:

- [$lookup](manual/reference/operator/aggregation/lookup) to do the following:

  - Join `customers` and `accounts` collections in the
    `sample_analytics` database based on the account ID of the
    customers and return the matching documents from the
    `accounts` collection in an array field named
    `purchases`.

  - Use [$search](pipe.$search) stage in the sub-pipeline to search
    for customer accounts that `must` have purchased both
    `CurrencyService` and `InvestmentStock` with preference
    for an order limit between `5000` to `10000`.

- [$limit](manual/reference/operator/aggregation/limit) stage to limit the output to `5` results.

- [$project](manual/reference/operator/aggregation/project) stage to exclude the specified fields in
  the results.

```cpp
#include <iostream>

#include <bsoncxx/builder/basic/document.hpp>
#include <bsoncxx/builder/basic/array.hpp>
#include <bsoncxx/json.hpp>
#include <mongocxx/client.hpp>
#include <mongocxx/instance.hpp>
#include <mongocxx/uri.hpp>
#include <mongocxx/pipeline.hpp>

using bsoncxx::builder::basic::kvp;
using bsoncxx::builder::basic::make_document;
using bsoncxx::builder::basic::make_array;

int main() {
    // Initialize the MongoDB C++ driver
    mongocxx::instance instance{};

    // Connect to your MongoDB deployment
    mongocxx::uri uri("<connection-string>");
    mongocxx::client client(uri);

    auto db = client["sample_analytics"];
    auto collection = db["customers"];

    // Build the aggregation pipeline
    mongocxx::pipeline pipeline{};

    // Create documents for the lookup pipeline stages
    auto search_doc = make_document(
        kvp("$search", make_document(
            kvp("index", "lookup-with-search-tutorial"),
            kvp("compound", make_document(
                kvp("must", make_array(
                    make_document(
                        kvp("queryString", make_document(
                            kvp("defaultPath", "products"),
                            kvp("query", "products: (CurrencyService AND InvestmentStock)")
                        ))
                    )
                )),
                kvp("should", make_array(
                    make_document(
                        kvp("range", make_document(
                            kvp("path", "limit"),
                            kvp("gte", 5000),
                            kvp("lte", 10000)
                        ))
                    )
                ))
            ))
        ))
    );


    auto limit_doc = make_document(kvp("$limit", 5));

    auto project_doc = make_document(
        kvp("$project", make_document(
            kvp("_id", 0),
            kvp("address", 0),
            kvp("birthdate", 0),
            kvp("username", 0),
            kvp("tier_and_details", 0)
        ))
    );

    auto lookup_pipeline_array = make_array(
        search_doc.view(),
        limit_doc.view(),
        project_doc.view()
    );

    pipeline.append_stage(make_document(
        kvp("$lookup", make_document(
            kvp("from", "accounts"),
            kvp("localField", "accounts"),
            kvp("foreignField", "account_id"),
            kvp("as", "purchases"),
            kvp("pipeline", lookup_pipeline_array.view())
        ))
    ));

    // Add $limit stage to the main pipeline
    pipeline.limit(5);

    // Add $project stage to the main pipeline
    pipeline.project(make_document(
        kvp("_id", 0),
        kvp("address", 0),
        kvp("birthdate", 0),
        kvp("username", 0),
        kvp("tier_and_details", 0)
    ));

    try {
        // Run the aggregation pipeline and print results
        auto cursor = collection.aggregate(pipeline);

        // Process and print the results
        for (auto&& doc : cursor) {
            std::cout << bsoncxx::to_json(doc) << std::endl;
        }
    } catch (const std::exception& e) {
        std::cerr << "Error executing query: " << e.what() << std::endl;
    }

    return 0;
}
```

Ensure that your connection string includes your database user's
credentials. To learn more, see [Driver](connect-via-driver).

**Input:**

```bash
c++ --std=c++17 lookup-with-search-query.cpp $(pkg-config --cflags --libs libmongocxx) -o ./o.out
./o.out
```

